for tx in block.transactions_recovered() {
    let txn = tx.into_inner();
    if let Some(spc_calls) = txn.spc_calls() {
        let async_context = AsyncContextFactory::verification_context(*txn.tx_hash(), spc_calls.clone());
        *strategy.evm_mut().ctx_mut().async_context_mut() = async_context;
    } else {
        let async_context = AsyncContextFactory::verification_context(*txn.tx_hash(), vec![]);
        *strategy.evm_mut().ctx_mut().async_context_mut() = async_context;
    }
    let gas_used = strategy.execute_transaction(tx)?;
}

